code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});

let str1, str2;
readline.on('line', line => {
    if (!str1) {
        str1 = line;
    } else if (!str2) {
        str2 = line;
        console.log(str1 + ' ' + str2);
        readline.close();
    }
});
